-- ============================================================
-- IMPORT ARSIP HISTORIS JOURNAL ENTRY
-- Tabel standalone, tidak berelasi ke skema utama
-- Jalankan di Supabase Dashboard → SQL Editor
-- ============================================================

DROP TABLE IF EXISTS public.journal_entry;

CREATE TABLE public.journal_entry (
  id              BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  number          TEXT,
  tanggal_tagihan DATE,
  siswa           TEXT,
  orang_tua       TEXT,
  komponen_tagihan TEXT,
  periode_tagihan  TEXT,
  ruang_kelas     TEXT,
  total_signed    NUMERIC(14,2),
  amount_due      NUMERIC(14,2),
  status          TEXT,
  payment_status  TEXT,
  created_at      TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- RLS: izinkan akses untuk authenticated user
ALTER TABLE public.journal_entry ENABLE ROW LEVEL SECURITY;
CREATE POLICY "all_authenticated_journal" ON public.journal_entry
  FOR ALL TO authenticated USING (true) WITH CHECK (true);

GRANT SELECT, INSERT, UPDATE, DELETE ON public.journal_entry TO authenticated;
GRANT USAGE, SELECT ON SEQUENCE public.journal_entry_id_seq TO authenticated;

